import React from 'react';
import { Swiper, SwiperSlide } from 'swiper/react';
import { Navigation, Pagination, Autoplay, EffectCreative } from 'swiper/modules';

// Swiper Stilleri
import 'swiper/css';
import 'swiper/css/navigation';
import 'swiper/css/pagination';
import 'swiper/css/effect-creative';

const slideData = [
  {
    id: 1,
    image: "https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?q=80&w=1920",
    subtitle: "Yeni Nesil Tasarım",
    title: "Dijital Dünyada \n Fark Yaratın",
    desc: "Yaratıcı çözümlerimizle markanızı bir adım öne taşıyoruz. Modern ve hızlı arayüzler."
  },
  {
    id: 2,
    image: "https://images.unsplash.com/photo-1614850523296-e8c041de4398?q=80&w=1920",
    subtitle: "Sınırsız Performans",
    title: "Hız ve Estetik \n Bir Arada",
    desc: "Kullanıcı deneyimini en üst seviyeye çıkaran, optimize edilmiş slider yapıları."
  }
];

const PremiumSlider = () => {
  return (
    <div className="relative w-full h-[85vh] min-h-[600px] overflow-hidden group">
      <Swiper
        modules={[Navigation, Pagination, Autoplay, EffectCreative]}
        grabCursor={true}
        effect={'creative'}
        creativeEffect={{
          prev: { shadow: true, translate: ['-20%', 0, -1] },
          next: { translate: ['100%', 0, 0] },
        }}
        loop={true}
        speed={800}
        autoplay={{ delay: 6000, disableOnInteraction: false }}
        navigation={{
          nextEl: '.next-btn',
          prevEl: '.prev-btn',
        }}
        pagination={{
          clickable: true,
          el: '.custom-pagination',
        }}
        className="w-full h-full"
      >
        {slideData.map((slide) => (
          <SwiperSlide key={slide.id} className="relative overflow-hidden">
            {/* Arka Plan Resmi + Kenar Yumuşatma */}
            <div className="absolute inset-0 scale-105 animate-slow-zoom">
              <img src={slide.image} alt="" className="w-full h-full object-cover" />
              <div className="absolute inset-0 bg-gradient-to-r from-black/80 via-black/40 to-transparent" />
            </div>

            {/* İçerik Alanı */}
            <div className="relative h-full container mx-auto px-6 flex flex-col justify-center items-start">
              <span className="inline-block py-1 px-4 mb-4 bg-blue-600 text-white text-xs font-bold uppercase tracking-widest rounded-full animate-bounce-subtle">
                {slide.subtitle}
              </span>
              <h1 className="text-5xl md:text-7xl font-black text-white leading-[1.1] mb-6 whitespace-pre-line drop-shadow-2xl">
                {slide.title}
              </h1>
              <p className="text-lg md:text-xl text-gray-300 max-w-xl mb-10 leading-relaxed italic border-l-4 border-blue-500 pl-6">
                {slide.desc}
              </p>
              <div className="flex items-center gap-5">
                <button className="bg-white text-black px-10 py-4 rounded-full font-bold hover:bg-blue-600 hover:text-white transition-all duration-500 shadow-xl">
                  Projeyi Gör
                </button>
                <button className="text-white border-b-2 border-white/30 hover:border-white py-2 transition-all">
                  Detaylı Bilgi
                </button>
              </div>
            </div>
          </SwiperSlide>
        ))}
      </Swiper>

      {/* Modern Özel Navigasyon Butonları */}
      <div className="absolute bottom-12 right-12 z-50 hidden md:flex gap-4">
        <button className="prev-btn w-14 h-14 rounded-full border border-white/20 flex items-center justify-center text-white hover:bg-white hover:text-black transition-all cursor-pointer backdrop-blur-md">
          ←
        </button>
        <button className="next-btn w-14 h-14 rounded-full border border-white/20 flex items-center justify-center text-white hover:bg-white hover:text-black transition-all cursor-pointer backdrop-blur-md">
          →
        </button>
      </div>

      {/* Özel Pagination (Çizgi Şeklinde) */}
      <div className="custom-pagination absolute bottom-12 left-1/2 -translate-x-1/2 md:left-32 md:translate-x-0 z-50 !w-auto flex gap-2"></div>

      <style jsx global>{`
        .custom-pagination .swiper-pagination-bullet {
          width: 40px;
          height: 4px;
          background: rgba(255,255,255,0.3) !important;
          border-radius: 2px;
          opacity: 1;
        }
        .custom-pagination .swiper-pagination-bullet-active {
          background: #2563eb !important;
          width: 60px;
        }
        @keyframes slow-zoom {
          from { transform: scale(1); }
          to { transform: scale(1.1); }
        }
        .animate-slow-zoom {
          animation: slow-zoom 20s infinite alternate ease-in-out;
        }
      `}</style>
    </div>
  );
};

export default PremiumSlider;
